import { useMemo, useRef } from "react";
import { useEvent } from "../hooks/use-event.js";
import { createSignal, useSelector } from "../signal/signal.js";
import {} from "../hooks/use-piece.js";
import { isRowSelected } from "./row-selection/is-row-selected.js";
import { isRowIndeterminate } from "./row-selection/is-row-indeterminate.js";
export function useRowByIndex(piece, globalSignal, state, rowParents) {
    const invalidateCacheRef = useRef(new Map());
    const atomCacheRef = useRef({});
    const rowInvalidate = useEvent((row) => {
        if (row == null) {
            globalSignal(Date.now());
        }
        else {
            const invalidate = invalidateCacheRef.current.get(row);
            invalidate?.(Date.now());
        }
    });
    const rowByIndex = useEvent((rowI) => {
        const atomCache = atomCacheRef.current;
        const invalidateCache = invalidateCacheRef.current;
        if (!atomCache[rowI]) {
            const $ = (x) => x[rowI] ?? null;
            const signal = createSignal(Date.now());
            invalidateCache.set(rowI, signal);
            atomCache[rowI] = {
                get: () => piece.get()[rowI],
                useValue: () => {
                    // Invalidate is used to invalidate an individual row,
                    // and the global signal will invalidate all rows.
                    const localSnapshot = useSelector(signal);
                    const globalSnapshot = useSelector(globalSignal);
                    const row = piece.useValue($);
                    const [selected, isIndeterminate] = useMemo(() => {
                        if (!row?.id)
                            return [false, false];
                        const selected = isRowSelected(row.id, state.rowSelections, rowParents);
                        return [
                            selected,
                            !selected &&
                                row.kind === "branch" &&
                                isRowIndeterminate(row.id, state.rowSelections, rowParents),
                        ];
                        // eslint-disable-next-line react-hooks/exhaustive-deps
                    }, [row?.id, localSnapshot, globalSnapshot]);
                    if (!row)
                        return null;
                    Object.assign(row, {
                        __selected: selected,
                        __indeterminate: isIndeterminate,
                        __localSnapshot: localSnapshot,
                        __globalSnapshot: globalSnapshot,
                    });
                    return row;
                },
            };
        }
        return atomCache[rowI];
    });
    return { rowInvalidate, rowByIndex };
}
